import { useTheme as useEmotionTheme } from '@emotion/react';
import isEqual from 'lodash/isEqual';
import type { ReactElement } from 'react';
import React from 'react';

import type { Theme } from '../../theme';
import { getTheme } from '../../theme';

export interface DesignSystemThemeInterface {
  /** Theme object that contains colors, spacing, and other variables **/
  theme: Theme;
  /** Prefix that is used in front of each className.  **/
  classNamePrefix: string;
  /** Helper method that use be used to construct the full className of an underlying AntD className.
   * Use with caution and prefer emotion.js when possible **/
  getPrefixedClassName: (className: string) => string;
}

export function getClassNamePrefix(theme: Theme): string {
  const antdThemeName = theme.isDarkMode ? 'dark' : 'light';
  return `${theme.general.classnamePrefix}-${antdThemeName}`;
}

export function getPrefixedClassNameFromTheme(theme: Theme, className: string | null | undefined): string {
  return [getClassNamePrefix(theme), className].filter(Boolean).join('-');
}

const canonicalThemeMap = new WeakMap<Theme, Theme>();
const canonicalThemes: Theme[] = [];

/**
 * Returns a canonical Theme instance for a given Theme object.
 *
 * Emotion (and some of our own utilities) tend to create new Theme object references even when
 * the underlying data is identical. That breaks reference-based caches like the WeakMap in
 * `getMemoizedButtonEmotionStyles`. We therefore keep a global list of canonical Theme objects and
 * reuse them whenever a new Theme object is structurally identical to one we've seen before.
 *
 * The method works in four steps:
 *   1. If we've already canonicalized this exact Theme reference, return it immediately (fast path).
 *   2. If this Theme reference is already present in `canonicalThemes`, reuse it.
 *   3. Otherwise, look for a previously canonicalized Theme whose shape matches via `isEqual`.
 *      When found, reuse that canonical Theme for the new reference.
 *   4. If no match exists, treat this Theme as a new canonical entry and remember it for future lookups.
 *
 * This gives us stable references across component instances without requiring callers to memoize
 * their overrides manually. The lists remain small (light/dark plus a few overrides), so the occasional
 * linear scan in the slow path is acceptable, and once a Theme is canonicalized, lookups hit the
 * WeakMap and become O(1).
 */
function getCanonicalTheme(theme: Theme): Theme {
  const cachedTheme = canonicalThemeMap.get(theme);
  if (cachedTheme) {
    return cachedTheme;
  }

  for (const existing of canonicalThemes) {
    if (existing === theme) {
      canonicalThemeMap.set(theme, existing);
      return existing;
    }
  }

  const matchedTheme = canonicalThemes.find((existing) => isEqual(existing, theme));
  if (matchedTheme) {
    canonicalThemeMap.set(theme, matchedTheme);
    return matchedTheme;
  }

  canonicalThemes.push(theme);
  canonicalThemeMap.set(theme, theme);
  return theme;
}

export function useDesignSystemTheme(): DesignSystemThemeInterface {
  const emotionTheme = useEmotionTheme() as Theme;
  // Graceful fallback to default theme in case a test or developer forgot context.
  const resolvedTheme =
    emotionTheme && emotionTheme.general
      ? emotionTheme
      : getTheme(false, {
          // Default values, safe to remove once the border colors flag is retired
          zIndexBase: 1000,
          enableAnimation: false,
        });

  // Canonicalize the theme to ensure we always return the same theme object for the same theme.
  // This is important to avoid unnecessary re-renders and inefficient EmotionCSS style generations.
  const theme = getCanonicalTheme(resolvedTheme);

  return {
    theme,
    classNamePrefix: getClassNamePrefix(theme),
    getPrefixedClassName: (className: string) => getPrefixedClassNameFromTheme(theme, className),
  };
}

export type DesignSystemHocProps = { designSystemThemeApi: DesignSystemThemeInterface };

// This is a simple typed HOC wrapper around the useDesignSystemTheme hook, for use in older react components.
export function WithDesignSystemThemeHoc<P>(
  Component: React.ComponentType<React.PropsWithChildren<P & DesignSystemHocProps>>,
) {
  return function WrappedWithDesignSystemTheme(props: P): ReactElement {
    const themeValues = useDesignSystemTheme();

    return <Component {...props} designSystemThemeApi={themeValues} />;
  };
}
